import os
from urllib.request import urlopen
from PIL import Image
import boto3

s3 = boto3.client('s3')

def take_screenshot(url):
    # Use headless Chrome or PhantomJS to generate a screenshot of the URL
    screenshot = os.popen("chrome --headless --disable-gpu --screenshot {}".format(url)).read()
    
    # Convert the screenshot to a PIL image object
    img = Image.open(BytesIO(screenshot))
    
    # Resize the image to a thumbnail size and save it to S3
    img.thumbnail((128, 128), Image.ANTIALIAS)
    s3.put_object(Body=img.tobytes(), Bucket='my-bucket', Key=url + '.jpg')
    
    # Return the URL of the thumbnail image on S3
    return "https://s3.amazonaws.com/my-bucket/" + url + ".jpg"